#include <iostream>
using namespace std;
int a[102]={0};
int main(){
    int n;
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i];
    for(int i=1;i<n;i++){
        for(int j=i+1;j<=n;j++){
            if(a[i]>a[j])swap(a[i],a[j]);
        }
    }
    int sum=n;
    for(int i=1;i<=n;i++){
        if(a[i]==a[i-1])sum--;
    }
    cout<<sum<<endl;
    for(int i=1;i<=n;i++){
        if(a[i]!=a[i-1])cout<<a[i]<<' ';
    }
    return 0;
}
